import java.io.FileWriter;
import java.io.IOException;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Output user input to the webpage with proper encoding
        try (FileWriter fileWriter = new FileWriter("output.html")) {
            fileWriter.write("<html>");
            fileWriter.write("<body>");
            fileWriter.write("<h1>User Input:</h1>");
            fileWriter.write(ESAPI.encoder().encodeForHTML(userInput)); // Properly encode user input
            fileWriter.write("</body>");
            fileWriter.write("</html>");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
